import React, { useState } from 'react';
import { searchDrugs, syncDrugs } from '@/utils/drugApi'; // API 경로 확인 필요
import './DrugPage.css'; // ⭐️ 위에서 만든 CSS 파일 import

export default function DrugPage() {
    const [keyword, setKeyword] = useState("");
    const [drugs, setDrugs] = useState([]);
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState("");

    // 페이지네이션 상태
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(0);

    // 데이터 조회 함수
    const fetchDrugs = async (searchKeyword, searchPage) => {
        setLoading(true);
        setMessage("데이터를 불러오는 중...");
        try {
            // API 호출 (keyword, page, size=10)
            const data = await searchDrugs(searchKeyword, searchPage, 10);
            
            setDrugs(data.content);
            setTotalPages(data.totalPages);
            setPage(data.number);

            if(data.totalElements === 0) {
                setMessage("검색 결과가 없습니다.");
            } else {
                setMessage("");
            }
        } catch (err) {
            setMessage("오류가 발생했습니다.");
            setDrugs([]);
        } finally {
            setLoading(false);
        }
    };

    // 검색 핸들러
    const handleSearch = (e) => {
        e.preventDefault();
        if (!keyword.trim()) return;
        setPage(0);
        fetchDrugs(keyword, 0);
    };

    // 페이지 변경 핸들러
    const handlePageChange = (newPage) => {
        if (newPage >= 0 && newPage < totalPages) {
            fetchDrugs(keyword, newPage);
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }
    };

    // 동기화 핸들러
    const handleSync = async () => {
        if (!confirm("데이터 동기화를 시작하시겠습니까? (시간이 소요됩니다)")) return;
        setLoading(true);
        setMessage("동기화 진행 중...");
        try {
            const resultMsg = await syncDrugs();
            setMessage("✅ " + resultMsg);
        } catch (err) {
            setMessage("❌ 동기화 실패");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="container">
            <h1 className="title">e약은요 검색</h1>

            {/* 검색 및 동기화 영역 */}
            <div className="searchBox">
                <form onSubmit={handleSearch} style={{ display: 'flex', width: '100%', gap: '10px', justifyContent: 'center' }}>
                    <input
                        type="text"
                        className="input"
                        placeholder="증상이나 약 이름을 입력하세요 (예: 두통)"
                        value={keyword}
                        onChange={(e) => setKeyword(e.target.value)}
                    />
                    <button type="submit" className="btn" disabled={loading}>
                        검색
                    </button>
                </form>
                {/* 동기화 버튼 (초록색 스타일 적용됨) */}
                <button onClick={handleSync} className="btn sync" disabled={loading}>
                    {loading ? "작업 중..." : "전체 동기화"}
                </button>
            </div>

            {/* 로딩 메시지 또는 결과 없음 메시지 */}
            {message && <div className="message">{message}</div>}

            {/* 결과 카드 리스트 */}
            {!loading && drugs.length > 0 && (
                <div className="grid">
                    {drugs.map((drug) => (
                        <div key={drug.itemSeq} className="card">
                            <div className="imgWrapper">
                                {drug.itemImage ? (
                                    <img src={drug.itemImage} alt={drug.itemName} />
                                ) : (
                                    <span style={{ color: '#ccc' }}>이미지 없음</span>
                                )}
                            </div>
                            <div className="content">
                                <span className="company">{drug.entpName}</span>
                                <h3 className="drugName">{drug.itemName}</h3>
                                <p className="info">
                                    <strong>효능:</strong> {drug.efficacy}
                                </p>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {/* 페이지네이션 (데이터가 있을 때만 표시) */}
            {!loading && drugs.length > 0 && (
                <div className="pagination-container">
                    <button 
                        className="page-btn"
                        onClick={() => handlePageChange(page - 1)}
                        disabled={page === 0}
                    >
                        &lt; 이전
                    </button>
                    
                    <span className="page-info">
                        Page <span className="current-page">{page + 1}</span> of {totalPages}
                    </span>

                    <button 
                        className="page-btn"
                        onClick={() => handlePageChange(page + 1)}
                        disabled={page >= totalPages - 1}
                    >
                        다음 &gt;
                    </button>
                </div>
            )}
        </div>
    );
}